"use client";

import React, { useState, useMemo } from "react";
import { useConfig } from "@/context/ConfigContext";
import {
    DndContext,
    closestCenter,
    KeyboardSensor,
    PointerSensor,
    useSensor,
    useSensors,
} from '@dnd-kit/core';
import {
    arrayMove,
    SortableContext,
    sortableKeyboardCoordinates,
    verticalListSortingStrategy,
} from '@dnd-kit/sortable';
import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Badge } from "@/components/ui/badge";
import { Trash2, Settings2, Plus, GripVertical, AlertCircle, ArrowDownAZ, ArrowUpZA, RotateCcw, Monitor, Maximize, Anchor, Star, Shuffle } from "lucide-react";
import { Checkbox } from "@/components/ui/checkbox";
import { Label } from "@/components/ui/label";

// Individual Sortable Item Component
function SortableCatalogItem({
    id,
    displayName,
    isEnabled,
    onRemove,
    onRename,
    settings,
    onUpdateSetting
}: {
    id: string,
    displayName: string,
    isEnabled: boolean,
    onRemove: () => void,
    onRename: (id: string, newName: string) => void,
    settings: {
        isSmall: boolean,
        isLandscape: boolean,
        isRandom: boolean,
        isPinned: boolean,
        isFeatured: boolean
    },
    onUpdateSetting: (key: string, value: boolean) => void
}) {
    const {
        attributes,
        listeners,
        setNodeRef,
        transform,
        transition,
        isDragging,
    } = useSortable({ id });

    const style = {
        transform: CSS.Transform.toString(transform),
        transition,
        zIndex: isDragging ? 10 : 1,
    };

    const [isEditing, setIsEditing] = useState(false);
    const [editValue, setEditValue] = useState(displayName);

    const handleRenameSubmit = () => {
        setIsEditing(false);
        if (editValue.trim() !== "" && editValue !== displayName) {
            onRename(id, editValue.trim());
        } else {
            setEditValue(displayName);
        }
    };

    return (
        <div
            ref={setNodeRef}
            style={style}
            className={`group flex items-center gap-3 p-3 bg-neutral-900 border border-neutral-800 rounded-lg mb-2 ${isDragging ? "opacity-50 border-blue-500 shadow-xl" : "hover:border-neutral-700"}`}
        >
            <button {...attributes} {...listeners} className="cursor-grab hover:text-white text-neutral-500 shrink-0" aria-label="Drag handle">
                <GripVertical className="h-4 w-4" />
            </button>

            <div className="flex-1 min-w-0">
                {isEditing ? (
                    <Input
                        value={editValue}
                        onChange={(e) => setEditValue(e.target.value)}
                        onBlur={handleRenameSubmit}
                        onKeyDown={(e) => e.key === 'Enter' && handleRenameSubmit()}
                        autoFocus
                        className="h-8 text-sm bg-neutral-950 border-blue-500"
                    />
                ) : (
                    <div className="flex flex-col cursor-pointer" onClick={() => setIsEditing(true)}>
                        <p className={`text-sm truncate font-medium text-neutral-200 flex items-center gap-2`}>
                            {displayName}
                            {settings.isPinned && <Anchor className="w-3 h-3 text-blue-400" />}
                            {settings.isFeatured && <Star className="w-3 h-3 text-amber-400" />}
                        </p>
                        <p className="text-[10px] text-neutral-500 truncate font-mono mt-0.5">{id}</p>
                    </div>
                )}
            </div>

            <div className="flex items-center gap-2 shrink-0">
                <div className="flex gap-1">
                    {settings.isSmall && <Badge variant="secondary" className="text-[9px] h-4 px-1 bg-neutral-800 text-neutral-400 border-none">Small</Badge>}
                    {settings.isLandscape && <Badge variant="secondary" className="text-[9px] h-4 px-1 bg-neutral-800 text-neutral-400 border-none">Wide</Badge>}
                    {settings.isRandom && <Badge variant="secondary" className="text-[9px] h-4 px-1 bg-neutral-800 text-neutral-400 border-none">Rand</Badge>}
                </div>

                <Popover>
                    <PopoverTrigger asChild>
                        <Button variant="ghost" size="icon" className="h-8 w-8 text-neutral-500 hover:text-white hover:bg-neutral-800">
                            <Settings2 className="w-4 h-4" />
                        </Button>
                    </PopoverTrigger>
                    <PopoverContent className="w-56 bg-neutral-900 border-neutral-800 p-3 shadow-2xl">
                        <div className="space-y-3">
                            <h4 className="text-xs font-bold uppercase text-neutral-500 mb-2">Catalog Settings</h4>

                            <div className="flex items-center space-x-2">
                                <Checkbox id={`small-${id}`} checked={settings.isSmall} onCheckedChange={(v) => onUpdateSetting("small_catalogs", !!v)} />
                                <Label htmlFor={`small-${id}`} className="text-xs text-neutral-300 flex items-center gap-2 cursor-pointer">
                                    <Monitor className="w-3.5 h-3.5" /> Small Size
                                </Label>
                            </div>

                            <div className="flex items-center space-x-2">
                                <Checkbox id={`landscape-${id}`} checked={settings.isLandscape} onCheckedChange={(v) => onUpdateSetting("landscape_catalogs", !!v)} />
                                <Label htmlFor={`landscape-${id}`} className="text-xs text-neutral-300 flex items-center gap-2 cursor-pointer">
                                    <Maximize className="w-3.5 h-3.5" /> Landscape Layout
                                </Label>
                            </div>

                            <div className="flex items-center space-x-2">
                                <Checkbox id={`random-${id}`} checked={settings.isRandom} onCheckedChange={(v) => onUpdateSetting("randomized_catalogs", !!v)} />
                                <Label htmlFor={`random-${id}`} className="text-xs text-neutral-300 flex items-center gap-2 cursor-pointer">
                                    <Shuffle className="w-3.5 h-3.5" /> Randomize Order
                                </Label>
                            </div>

                            <div className="h-px bg-neutral-800 my-2" />

                            <div className="flex items-center space-x-2">
                                <Checkbox id={`pinned-${id}`} checked={settings.isPinned} onCheckedChange={(v) => onUpdateSetting("pinned_catalogs", !!v)} />
                                <Label htmlFor={`pinned-${id}`} className="text-xs text-neutral-300 flex items-center gap-2 cursor-pointer">
                                    <Anchor className="w-3.5 h-3.5 text-blue-400" /> Pinned
                                </Label>
                            </div>

                            <div className="flex items-center space-x-2">
                                <Checkbox id={`featured-${id}`} checked={settings.isFeatured} onCheckedChange={(v) => onUpdateSetting("top_row_catalogs", !!v)} />
                                <Label htmlFor={`featured-${id}`} className="text-xs text-neutral-300 flex items-center gap-2 cursor-pointer">
                                    <Star className="w-3.5 h-3.5 text-amber-400" /> Featured (Top Row)
                                </Label>
                            </div>
                        </div>
                    </PopoverContent>
                </Popover>

                <Button
                    variant="ghost"
                    size="icon"
                    onClick={onRemove}
                    className="h-8 w-8 text-neutral-600 hover:text-red-500 hover:bg-red-500/10 transition-colors"
                >
                    <Trash2 className="w-4 h-4" />
                </Button>
            </div>
        </div>
    );
}

export function CatalogEditor() {
    const { initialValues, currentValues, updateValue, toggleCatalog, removeCatalog } = useConfig();
    const [searchTerm, setSearchTerm] = useState("");

    const catalogsKey = currentValues["catalog_ordering"] ? "catalog_ordering" :
        currentValues["selected_catalogs"] ? "selected_catalogs" : null;

    const catalogItems: string[] = catalogsKey ? (currentValues[catalogsKey] || []) : [];
    const [items, setItems] = useState(catalogItems);
    const customNames = currentValues["custom_catalog_names"] || {};

    React.useEffect(() => {
        setItems(catalogItems);
    }, [JSON.stringify(catalogItems)]);

    const sensors = useSensors(
        useSensor(PointerSensor),
        useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
    );

    const handleUpdateSetting = (catalogId: string, listKey: string, active: boolean) => {
        const currentList = Array.isArray(currentValues[listKey]) ? currentValues[listKey] : [];
        let newList;
        if (active) {
            newList = Array.from(new Set([...currentList, catalogId]));
        } else {
            newList = currentList.filter((id: string) => id !== catalogId);
        }
        updateValue([listKey], newList);
    };

    const handleDragEnd = (event: any) => {
        const { active, over } = event;
        if (active.id !== over.id) {
            const oldIndex = items.indexOf(active.id);
            const newIndex = items.indexOf(over.id);
            const newArray = arrayMove(items, oldIndex, newIndex);
            setItems(newArray);
            updateValue([catalogsKey || "catalog_ordering"], newArray);
        }
    };

    const handleAddCatalog = (catalogId: string) => {
        const newArray = [...items, catalogId];
        setItems(newArray);
        updateValue([catalogsKey || "catalog_ordering"], newArray);
        // Also ensure it's in selected_catalogs if that exists separately
        if (currentValues["selected_catalogs"] && !currentValues["selected_catalogs"].includes(catalogId)) {
            updateValue(["selected_catalogs"], [...currentValues["selected_catalogs"], catalogId]);
        }
    };

    const availableToAdding = useMemo(() => {
        return Object.entries(customNames as Record<string, string>)
            .filter(([id, name]) => {
                const hasName = name && name.trim() !== "" && name !== id;
                const isNotInternal = !id.startsWith("_");
                const isAlreadyIn = items.includes(id);
                return hasName && isNotInternal && !isAlreadyIn;
            })
            .sort((a, b) => a[1].localeCompare(b[1]));
    }, [customNames, items]);

    if (!catalogsKey) {
        return (
            <div className="p-4 text-sm text-yellow-500 bg-yellow-500/10 border border-yellow-500/20 rounded-md flex gap-2 items-start">
                <AlertCircle className="w-4 h-4 mt-0.5 shrink-0" />
                <span>Could not locate catalog lists.</span>
            </div>
        );
    }

    return (
        <div className="space-y-4">
            <p className="text-sm text-neutral-400">
                Manage global catalog settings and ordering. Changes here affect the root level catalog shelf.
            </p>

            <div className="flex flex-wrap items-center gap-2 mb-4 bg-neutral-900/50 p-2 rounded-lg border border-neutral-800">
                <Button variant="outline" size="sm" onClick={() => updateValue([catalogsKey], [...items].sort())} className="h-8 text-xs border-neutral-700">
                    <ArrowDownAZ className="w-4 h-4 mr-2" /> A-Z
                </Button>
                <Button variant="outline" size="sm" onClick={() => updateValue([catalogsKey], [...items].sort().reverse())} className="h-8 text-xs border-neutral-700">
                    <ArrowUpZA className="w-4 h-4 mr-2" /> Z-A
                </Button>
                <div className="w-px h-5 bg-neutral-800 mx-2" />

                <Popover>
                    <PopoverTrigger asChild>
                        <Button variant="outline" size="sm" className="h-8 text-xs bg-blue-600 hover:bg-blue-500 text-white border-transparent">
                            <Plus className="w-4 h-4 mr-2" /> Add Catalog
                        </Button>
                    </PopoverTrigger>
                    <PopoverContent className="w-72 bg-neutral-900 border-neutral-800 p-0 shadow-2xl overflow-hidden">
                        <div className="p-3 border-b border-neutral-800 bg-neutral-950">
                            <h4 className="text-xs font-bold uppercase text-neutral-400">Add Named Catalog</h4>
                            <p className="text-[10px] text-neutral-500 mt-1">Showing catalogs with custom names.</p>
                        </div>
                        <div className="max-h-[300px] overflow-y-auto p-1 custom-scrollbar">
                            {availableToAdding.length === 0 ? (
                                <p className="text-[10px] text-neutral-600 p-4 text-center">No more named catalogs available.</p>
                            ) : (
                                availableToAdding.map(([id, name]) => (
                                    <button
                                        key={id}
                                        onClick={() => handleAddCatalog(id)}
                                        className="w-full flex flex-col items-start p-2 rounded hover:bg-blue-500/10 hover:text-blue-400 text-left transition-colors group"
                                    >
                                        <span className="text-sm font-medium">{name}</span>
                                        <span className="text-[9px] text-neutral-500 font-mono group-hover:text-blue-500/50">{id}</span>
                                    </button>
                                ))
                            )}
                        </div>
                    </PopoverContent>
                </Popover>
            </div>

            <DndContext sensors={sensors} collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
                <SortableContext items={items} strategy={verticalListSortingStrategy}>
                    <div className="space-y-0.5 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
                        {items.map((id) => (
                            <SortableCatalogItem
                                key={id}
                                id={id}
                                displayName={customNames[id] || id}
                                isEnabled={true}
                                onRemove={() => removeCatalog(id)}
                                onRename={(id, newN) => updateValue(["custom_catalog_names", id], newN)}
                                settings={{
                                    isSmall: (currentValues["small_catalogs"] || []).includes(id),
                                    isLandscape: (currentValues["landscape_catalogs"] || []).includes(id),
                                    isRandom: (currentValues["randomized_catalogs"] || []).includes(id),
                                    isPinned: (currentValues["pinned_catalogs"] || []).includes(id),
                                    isFeatured: (currentValues["top_row_catalogs"] || []).includes(id)
                                }}
                                onUpdateSetting={(key, val) => handleUpdateSetting(id, key, val)}
                            />
                        ))}
                    </div>
                </SortableContext>
            </DndContext>
        </div>
    );
}
